FROM generate_series(1, 1000) s(i)
ON CONFLICT (a, c) DO NOTHING;
INSERT INTO revalidation.r2_ex5 (a, b, c, d)
SELECT r1.a, r1.b, r1.c, (random() * 100 + 1)::int
