DROP TABLE IF EXISTS revalidation.result_ex157 CASCADE;
CREATE TABLE revalidation.r1_ex157 (a INTEGER, b INTEGER, v1 INTEGER, PRIMARY KEY (a));
CREATE TABLE revalidation.r2_ex157 (a INTEGER, b INTEGER, v2 INTEGER, PRIMARY KEY (a, b));
INSERT INTO revalidation.r1_ex157 (a, b, v1)
SELECT ((i / 1) % 100 + 1)::int, ((i * 10) % 47 + 1)::int, (random() * 100 + 1)::int
FROM generate_series(1, 1000) s(i)
ON CONFLICT (a) DO NOTHING;
INSERT INTO revalidation.r2_ex157 (a, b, v2)
SELECT r1.a, r1.b, (random() * 100 + 1)::int
FROM revalidation.r1_ex157 r1
ORDER BY random()
ON CONFLICT (a, b) DO NOTHING;
CREATE TABLE revalidation.result_ex157 (a INTEGER, b INTEGER, v1 INTEGER, v2 INTEGER);
INSERT INTO revalidation.result_ex157
SELECT DISTINCT r1.a, r1.b, r1.v1, r2.v2
FROM revalidation.r1_ex157 r1
INNER JOIN revalidation.r2_ex157 r2 ON r1.a = r2.a AND r1.b = r2.b;

DO $$
DECLARE
    total_rows BIGINT;
    unique_count BIGINT;
    reduced_count BIGINT;
    -- Paper grain
    p_unique BOOLEAN;
    p_minimal BOOLEAN := TRUE;
    p_removable TEXT := '';
    -- Corrected grain
    c_unique BOOLEAN;
    c_minimal BOOLEAN := TRUE;
    c_removable TEXT := '';
    -- Temp
    col_to_remove TEXT;
    reduced_cols TEXT;
    grain_cols TEXT[];
    i INTEGER;
BEGIN
    SELECT COUNT(*) INTO total_rows FROM revalidation.result_ex157;

    IF total_rows = 0 THEN
        INSERT INTO revalidation.test_results VALUES (
            157, 'Main Theorem', 'A', 'Case A — Jk={a,b}, G1={a}, G2={a,b} [v7]',
            0, 'a', FALSE, FALSE, 'NO DATA',
            'a', FALSE, FALSE, 'NO DATA'
        );
        RAISE NOTICE 'Ex 157: NO JOIN RESULTS (0 rows)';
        RETURN;
    END IF;

    -- ── Test paper grain: uniqueness ──
    SELECT COUNT(DISTINCT (a)) INTO unique_count FROM revalidation.result_ex157;
    p_unique := (total_rows = unique_count);

    -- ── Test paper grain: minimality ──
    grain_cols := ARRAY['a'];
    IF p_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex157', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                p_minimal := FALSE;
                IF p_removable != '' THEN p_removable := p_removable || ', '; END IF;
                p_removable := p_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    -- ── Test corrected grain: uniqueness ──
    SELECT COUNT(DISTINCT (a)) INTO unique_count FROM revalidation.result_ex157;
    c_unique := (total_rows = unique_count);

    -- ── Test corrected grain: minimality ──
    grain_cols := ARRAY['a'];
    IF c_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex157', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                c_minimal := FALSE;
                IF c_removable != '' THEN c_removable := c_removable || ', '; END IF;
                c_removable := c_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    IF p_removable = '' THEN p_removable := '-'; END IF;
    IF c_removable = '' THEN c_removable := '-'; END IF;

    INSERT INTO revalidation.test_results VALUES (
        157, 'Main Theorem', 'A', 'Case A — Jk={a,b}, G1={a}, G2={a,b} [v7]',
        total_rows, 'a', p_unique, p_minimal, p_removable,
        'a', c_unique, c_minimal, c_removable
    );

    RAISE NOTICE 'Ex %: rows=% | paper(%): uniq=% min=% rem=% | corrected(%): uniq=% min=%',
        157, total_rows,
        'a', p_unique, p_minimal, p_removable,
        'a', c_unique, c_minimal;

EXCEPTION WHEN OTHERS THEN
    INSERT INTO revalidation.test_results VALUES (
        157, 'Main Theorem', 'A', 'Case A — Jk={a,b}, G1={a}, G2={a,b} [v7]',
        -1, 'a', FALSE, FALSE, 'ERROR: ' || SQLERRM,
        'a', FALSE, FALSE, 'ERROR: ' || SQLERRM
    );
    RAISE NOTICE 'Ex %: ERROR - %', 157, SQLERRM;
END $$;

