DROP TABLE IF EXISTS revalidation.r2_ex289 CASCADE;
DROP TABLE IF EXISTS revalidation.result_ex289 CASCADE;
CREATE TABLE revalidation.r1_ex289 (a INTEGER, b INTEGER, c INTEGER, v1 INTEGER, PRIMARY KEY (a, b, c));
CREATE TABLE revalidation.r2_ex289 (a INTEGER, b INTEGER, d INTEGER, v2 INTEGER, PRIMARY KEY (a, b, d));
INSERT INTO revalidation.r1_ex289 (a, b, c, v1)
SELECT ((i / 36) % 3 + 1)::int, ((i / 12) % 3 + 1)::int, ((i / 1) % 12 + 1)::int, (random() * 100 + 1)::int
FROM generate_series(1, 1000) s(i)
ON CONFLICT (a, b, c) DO NOTHING;
INSERT INTO revalidation.r2_ex289 (a, b, d, v2)
SELECT r1.a, r1.b, s_d.d, (random() * 100 + 1)::int
FROM revalidation.r1_ex289 r1
    CROSS JOIN generate_series(1, 12) s_d(d)
ORDER BY random()
ON CONFLICT (a, b, d) DO NOTHING;
CREATE TABLE revalidation.result_ex289 (a INTEGER, b INTEGER, c INTEGER, v1 INTEGER, d INTEGER, v2 INTEGER);
INSERT INTO revalidation.result_ex289
SELECT DISTINCT r1.a, r1.b, r1.c, r1.v1, r2.d, r2.v2
FROM revalidation.r1_ex289 r1
INNER JOIN revalidation.r2_ex289 r2 ON r1.a = r2.a AND r1.b = r2.b;

DO $$
DECLARE
    total_rows BIGINT;
    unique_count BIGINT;
    reduced_count BIGINT;
    -- Paper grain
    p_unique BOOLEAN;
    p_minimal BOOLEAN := TRUE;
    p_removable TEXT := '';
    -- Corrected grain
    c_unique BOOLEAN;
    c_minimal BOOLEAN := TRUE;
    c_removable TEXT := '';
    -- Temp
    col_to_remove TEXT;
    reduced_cols TEXT;
    grain_cols TEXT[];
    i INTEGER;
BEGIN
    SELECT COUNT(*) INTO total_rows FROM revalidation.result_ex289;

    IF total_rows = 0 THEN
        INSERT INTO revalidation.test_results VALUES (
            289, 'Incomparable Grains', 'A', 'Case A — Jk={a,b}, G1={a,b,c}, G2={a,b,d} [v4]',
            0, 'a, b, c, d', FALSE, FALSE, 'NO DATA',
            'a, b, c, d', FALSE, FALSE, 'NO DATA'
        );
        RAISE NOTICE 'Ex 289: NO JOIN RESULTS (0 rows)';
        RETURN;
    END IF;

    -- ── Test paper grain: uniqueness ──
    SELECT COUNT(DISTINCT (a, b, c, d)) INTO unique_count FROM revalidation.result_ex289;
    p_unique := (total_rows = unique_count);

    -- ── Test paper grain: minimality ──
    grain_cols := ARRAY['a', 'b', 'c', 'd'];
    IF p_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex289', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                p_minimal := FALSE;
                IF p_removable != '' THEN p_removable := p_removable || ', '; END IF;
                p_removable := p_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    -- ── Test corrected grain: uniqueness ──
    SELECT COUNT(DISTINCT (a, b, c, d)) INTO unique_count FROM revalidation.result_ex289;
    c_unique := (total_rows = unique_count);

    -- ── Test corrected grain: minimality ──
    grain_cols := ARRAY['a', 'b', 'c', 'd'];
    IF c_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex289', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                c_minimal := FALSE;
                IF c_removable != '' THEN c_removable := c_removable || ', '; END IF;
                c_removable := c_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    IF p_removable = '' THEN p_removable := '-'; END IF;
    IF c_removable = '' THEN c_removable := '-'; END IF;

    INSERT INTO revalidation.test_results VALUES (
        289, 'Incomparable Grains', 'A', 'Case A — Jk={a,b}, G1={a,b,c}, G2={a,b,d} [v4]',
        total_rows, 'a, b, c, d', p_unique, p_minimal, p_removable,
        'a, b, c, d', c_unique, c_minimal, c_removable
    );

    RAISE NOTICE 'Ex %: rows=% | paper(%): uniq=% min=% rem=% | corrected(%): uniq=% min=%',
        289, total_rows,
        'a, b, c, d', p_unique, p_minimal, p_removable,
        'a, b, c, d', c_unique, c_minimal;

EXCEPTION WHEN OTHERS THEN
    INSERT INTO revalidation.test_results VALUES (
        289, 'Incomparable Grains', 'A', 'Case A — Jk={a,b}, G1={a,b,c}, G2={a,b,d} [v4]',
        -1, 'a, b, c, d', FALSE, FALSE, 'ERROR: ' || SQLERRM,
        'a, b, c, d', FALSE, FALSE, 'ERROR: ' || SQLERRM
    );
    RAISE NOTICE 'Ex %: ERROR - %', 289, SQLERRM;
END $$;

