        -1, 'a, b', FALSE, FALSE, 'ERROR: ' || SQLERRM,
        'a, b', FALSE, FALSE, 'ERROR: ' || SQLERRM
    );
    RAISE NOTICE 'Ex %: ERROR - %', 342, SQLERRM;
END $$;

