FROM revalidation.r1_ex181 r1
INNER JOIN revalidation.r2_ex181 r2 ON r1.g1 = r2.g1;

DO $$
DECLARE
    total_rows BIGINT;
    unique_count BIGINT;
    reduced_count BIGINT;
    -- Paper grain
    p_unique BOOLEAN;
    p_minimal BOOLEAN := TRUE;
    p_removable TEXT := '';
    -- Corrected grain
    c_unique BOOLEAN;
    c_minimal BOOLEAN := TRUE;
    c_removable TEXT := '';
    -- Temp
    col_to_remove TEXT;
    reduced_cols TEXT;
    grain_cols TEXT[];
    i INTEGER;
BEGIN
    SELECT COUNT(*) INTO total_rows FROM revalidation.result_ex181;

    IF total_rows = 0 THEN
        INSERT INTO revalidation.test_results VALUES (
            181, 'Equal Grains', 'A', 'Equal grains |G|=1, |Jk|=1 [v1]',
            0, 'g1', FALSE, FALSE, 'NO DATA',
            'g1', FALSE, FALSE, 'NO DATA'
        );
        RAISE NOTICE 'Ex 181: NO JOIN RESULTS (0 rows)';
        RETURN;
    END IF;

    -- ── Test paper grain: uniqueness ──
    SELECT COUNT(DISTINCT (g1)) INTO unique_count FROM revalidation.result_ex181;
    p_unique := (total_rows = unique_count);

    -- ── Test paper grain: minimality ──
    grain_cols := ARRAY['g1'];
    IF p_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex181', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                p_minimal := FALSE;
                IF p_removable != '' THEN p_removable := p_removable || ', '; END IF;
                p_removable := p_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    -- ── Test corrected grain: uniqueness ──
    SELECT COUNT(DISTINCT (g1)) INTO unique_count FROM revalidation.result_ex181;
