DROP TABLE IF EXISTS revalidation.r2_ex210 CASCADE;
DROP TABLE IF EXISTS revalidation.result_ex210 CASCADE;
CREATE TABLE revalidation.r1_ex210 (g1 INTEGER, g2 INTEGER, g3 INTEGER, v1 INTEGER, PRIMARY KEY (g1, g2, g3));
CREATE TABLE revalidation.r2_ex210 (g1 INTEGER, g2 INTEGER, g3 INTEGER, v2 INTEGER, PRIMARY KEY (g1, g2, g3));
INSERT INTO revalidation.r1_ex210 (g1, g2, g3, v1)
SELECT ((i / 64) % 15 + 1)::int, ((i / 8) % 8 + 1)::int, ((i / 1) % 8 + 1)::int, (random() * 100 + 1)::int
FROM generate_series(1, 1000) s(i)
ON CONFLICT (g1, g2, g3) DO NOTHING;
INSERT INTO revalidation.r2_ex210 (g1, g2, g3, v2)
SELECT r1.g1, r1.g2, s_g3.g3, (random() * 100 + 1)::int
FROM revalidation.r1_ex210 r1
    CROSS JOIN generate_series(1, 8) s_g3(g3)
ORDER BY random()
ON CONFLICT (g1, g2, g3) DO NOTHING;
CREATE TABLE revalidation.result_ex210 (g1 INTEGER, g2 INTEGER, g3_r1 INTEGER, g3_r2 INTEGER, v1 INTEGER, v2 INTEGER);
INSERT INTO revalidation.result_ex210
SELECT DISTINCT r1.g1, r1.g2, r1.g3 AS g3_r1, r2.g3 AS g3_r2, r1.v1, r2.v2
FROM revalidation.r1_ex210 r1
INNER JOIN revalidation.r2_ex210 r2 ON r1.g1 = r2.g1 AND r1.g2 = r2.g2;

DO $$
DECLARE
    total_rows BIGINT;
    unique_count BIGINT;
    reduced_count BIGINT;
    -- Paper grain
    p_unique BOOLEAN;
    p_minimal BOOLEAN := TRUE;
    p_removable TEXT := '';
    -- Corrected grain
    c_unique BOOLEAN;
    c_minimal BOOLEAN := TRUE;
    c_removable TEXT := '';
    -- Temp
    col_to_remove TEXT;
    reduced_cols TEXT;
    grain_cols TEXT[];
    i INTEGER;
BEGIN
    SELECT COUNT(*) INTO total_rows FROM revalidation.result_ex210;

    IF total_rows = 0 THEN
        INSERT INTO revalidation.test_results VALUES (
            210, 'Equal Grains', 'A', 'Equal grains |G|=3, |Jk|=2 [v30]',
            0, 'g3_r1, g3_r2, g1, g2', FALSE, FALSE, 'NO DATA',
            'g3_r1, g3_r2, g1, g2', FALSE, FALSE, 'NO DATA'
        );
        RAISE NOTICE 'Ex 210: NO JOIN RESULTS (0 rows)';
        RETURN;
    END IF;

    -- ── Test paper grain: uniqueness ──
    SELECT COUNT(DISTINCT (g3_r1, g3_r2, g1, g2)) INTO unique_count FROM revalidation.result_ex210;
    p_unique := (total_rows = unique_count);

    -- ── Test paper grain: minimality ──
    grain_cols := ARRAY['g3_r1', 'g3_r2', 'g1', 'g2'];
    IF p_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex210', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                p_minimal := FALSE;
                IF p_removable != '' THEN p_removable := p_removable || ', '; END IF;
                p_removable := p_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    -- ── Test corrected grain: uniqueness ──
    SELECT COUNT(DISTINCT (g3_r1, g3_r2, g1, g2)) INTO unique_count FROM revalidation.result_ex210;
    c_unique := (total_rows = unique_count);

    -- ── Test corrected grain: minimality ──
    grain_cols := ARRAY['g3_r1', 'g3_r2', 'g1', 'g2'];
    IF c_unique AND array_length(grain_cols, 1) > 1 THEN
        FOR i IN 1..array_length(grain_cols, 1) LOOP
            reduced_cols := '';
            FOR j IN 1..array_length(grain_cols, 1) LOOP
                IF j != i THEN
                    IF reduced_cols != '' THEN reduced_cols := reduced_cols || ', '; END IF;
                    reduced_cols := reduced_cols || grain_cols[j];
                END IF;
            END LOOP;
            EXECUTE format('SELECT COUNT(DISTINCT (%s)) FROM revalidation.result_ex210', reduced_cols)
                INTO reduced_count;
            IF reduced_count = total_rows THEN
                c_minimal := FALSE;
                IF c_removable != '' THEN c_removable := c_removable || ', '; END IF;
                c_removable := c_removable || grain_cols[i];
            END IF;
        END LOOP;
    END IF;

    IF p_removable = '' THEN p_removable := '-'; END IF;
    IF c_removable = '' THEN c_removable := '-'; END IF;

    INSERT INTO revalidation.test_results VALUES (
        210, 'Equal Grains', 'A', 'Equal grains |G|=3, |Jk|=2 [v30]',
        total_rows, 'g3_r1, g3_r2, g1, g2', p_unique, p_minimal, p_removable,
        'g3_r1, g3_r2, g1, g2', c_unique, c_minimal, c_removable
    );

    RAISE NOTICE 'Ex %: rows=% | paper(%): uniq=% min=% rem=% | corrected(%): uniq=% min=%',
        210, total_rows,
        'g3_r1, g3_r2, g1, g2', p_unique, p_minimal, p_removable,
        'g3_r1, g3_r2, g1, g2', c_unique, c_minimal;

EXCEPTION WHEN OTHERS THEN
    INSERT INTO revalidation.test_results VALUES (
        210, 'Equal Grains', 'A', 'Equal grains |G|=3, |Jk|=2 [v30]',
        -1, 'g3_r1, g3_r2, g1, g2', FALSE, FALSE, 'ERROR: ' || SQLERRM,
        'g3_r1, g3_r2, g1, g2', FALSE, FALSE, 'ERROR: ' || SQLERRM
    );
    RAISE NOTICE 'Ex %: ERROR - %', 210, SQLERRM;
END $$;

